def runKthLargest(operations, values):
    obj = None
    results = []
    for op, val in zip(operations, values):
        if op == 'KthLargest':
            obj = KthLargest(val[0], val[1])
            results.append(None)
        elif op == 'add':
            results.append(obj.add(val[0]))
    return results

