def verify(actual_output, expected_output):
    """Verify the KthLargest operations result"""
    def list_to_string(lst):
        if not lst:
            return '[]'
        return '[' + ', '.join(str(x) if x is not None else 'null' for x in lst) + ']'

    passed = True
    if len(actual_output) != len(expected_output):
        passed = False
    else:
        for actual, expected in zip(actual_output, expected_output):
            if expected is None:
                if actual is not None:
                    passed = False
                    break
            elif actual != expected:
                passed = False
                break

    return [passed, list_to_string(actual_output)]
